import logging
import logging.handlers
import os
import stat
from pathlib import Path
from datetime import datetime


class SecureLogger:
    def __init__(self, log_dir='logs', app_name='myapp', max_bytes=10485760, backup_count=5):
        self.log_dir = Path(log_dir)
        self.app_name = app_name
        self.max_bytes = max_bytes
        self.backup_count = backup_count
        self.logger = None
        
        self._setup_logging()
    
    def _create_secure_log_directory(self):
        if not self.log_dir.exists():
            self.log_dir.mkdir(parents=True, exist_ok=True)
        
        os.chmod(self.log_dir, stat.S_IRWXU)
    
    def _set_secure_file_permissions(self, filepath):
        os.chmod(filepath, stat.S_IRUSR | stat.S_IWUSR)
    
    def _setup_logging(self):
        self._create_secure_log_directory()
        
        log_filename = self.log_dir / f'{self.app_name}.log'
        
        if not log_filename.exists():
            log_filename.touch()
            self._set_secure_file_permissions(log_filename)
        
        self.logger = logging.getLogger(self.app_name)
        self.logger.setLevel(logging.DEBUG)
        
        if self.logger.handlers:
            self.logger.handlers.clear()
        
        file_handler = logging.handlers.RotatingFileHandler(
            log_filename,
            maxBytes=self.max_bytes,
            backupCount=self.backup_count,
            encoding='utf-8'
        )
        
        file_handler.rotator = self._secure_rotator
        file_handler.namer = self._custom_namer
        
        formatter = logging.Formatter(
            '%(asctime)s - %(name)s - %(levelname)s - %(filename)s:%(lineno)d - %(message)s',
            datefmt='%Y-%m-%d %H:%M:%S'
        )
        file_handler.setFormatter(formatter)
        
        console_handler = logging.StreamHandler()
        console_handler.setLevel(logging.INFO)
        console_handler.setFormatter(formatter)
        
        self.logger.addHandler(file_handler)
        self.logger.addHandler(console_handler)
    
    def _secure_rotator(self, source, dest):
        if os.path.exists(source):
            os.rename(source, dest)
            self._set_secure_file_permissions(dest)
    
    def _custom_namer(self, default_name):
        base_filename = os.path.basename(default_name)
        dir_name = os.path.dirname(default_name)
        
        if base_filename.endswith('.log'):
            base_filename = base_filename[:-4]
        
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        return os.path.join(dir_name, f'{base_filename}_{timestamp}.log')
    
    def get_logger(self):
        return self.logger
    
    def debug(self, message):
        self.logger.debug(self._sanitize_message(message))
    
    def info(self, message):
        self.logger.info(self._sanitize_message(message))
    
    def warning(self, message):
        self.logger.warning(self._sanitize_message(message))
    
    def error(self, message):
        self.logger.error(self._sanitize_message(message))
    
    def critical(self, message):
        self.logger.critical(self._sanitize_message(message))
    
    def _sanitize_message(self, message):
        if isinstance(message, str):
            message = message.replace('\n', ' ').replace('\r', ' ')
            
            sensitive_patterns = ['password', 'token', 'secret', 'api_key', 'apikey']
            message_lower = message.lower()
            
            for pattern in sensitive_patterns:
                if pattern in message_lower:
                    return '[REDACTED - Sensitive Information]'
        
        return message


